import { useLocalStorage } from '@vueuse/core'
import { defineStore } from 'pinia'
import { ref } from 'vue'

const STICKER_SCALE_STORAGE_KEY = 'Comfy.GFV.NodeStickerScale'
const DEFAULT_STICKER_SCALE = 1.5

/** Floating panel toggled with Z / Comfy.Canvas.NodeShapePalette — pick a node sticker. */
export const useNodeStickerPaletteStore = defineStore('nodeStickerPalette', () => {
  const paletteOpen = ref(false)
  /** Client-only (localStorage). Not sent to /settings — avoids backend rejecting unknown keys. */
  const stickerScale = useLocalStorage(STICKER_SCALE_STORAGE_KEY, DEFAULT_STICKER_SCALE)

  function openPalette() {
    paletteOpen.value = true
  }

  function closePalette() {
    paletteOpen.value = false
  }

  function togglePalette() {
    paletteOpen.value = !paletteOpen.value
  }

  return {
    paletteOpen,
    stickerScale,
    openPalette,
    closePalette,
    togglePalette
  }
})
