import type { LGraphNode } from '@/lib/litegraph/src/litegraph'
import { LiteGraph } from '@/lib/litegraph/src/litegraph'
import { NODE_STICKER_BASE_CANVAS_FONT_PX } from '@/constants/nodeStickers'
import { getNodeStickerScaleSafe } from '@/utils/nodeStickerScale'

/** Emoji fallback when nodes render on canvas (Classic / Nodes 2.0 off). */
export const NODE_STICKER_CANVAS_EMOJI: Record<string, string> = {
  lightbulb: '💡',
  skull: '💀',
  heart: '❤️',
  star: '⭐',
  sparkles: '✨',
  flame: '🔥'
}

/**
 * Draw GFV sticker above the top-left corner (node-local coords; title is y &lt; 0).
 * Only used when {@link LiteGraph.vueNodesMode} is false — DOM overlay is skipped then.
 */
export function drawGfvNodeStickerOnCanvas(
  node: LGraphNode,
  ctx: CanvasRenderingContext2D,
  dsScale: number
): void {
  const raw = node.properties?.gfvSticker
  if (typeof raw !== 'string' || !raw.length) return
  const emoji = NODE_STICKER_CANVAS_EMOJI[raw]
  if (!emoji) return

  const titleH = LiteGraph.NODE_TITLE_HEIGHT
  const stickerScale = getNodeStickerScaleSafe()
  ctx.save()
  const ds = Math.max(0.5, Math.min(dsScale, 2.5))
  const fontPx = NODE_STICKER_BASE_CANVAS_FONT_PX * ds * stickerScale
  ctx.font = `${fontPx}px "Segoe UI Emoji","Apple Color Emoji","Noto Color Emoji",sans-serif`
  ctx.textAlign = 'left'
  ctx.textBaseline = 'middle'
  ctx.fillStyle = '#fbbf24'
  const gap = 4 * ds
  const cx = gap + fontPx * 0.35
  const cy = -titleH - gap - fontPx * 0.5
  ctx.fillText(emoji, cx, cy)
  ctx.restore()
}
