/** Base Vue badge size (px) before user sticker scale (localStorage via palette store). */
export const NODE_STICKER_BASE_BADGE_PX = 28
/** Base icon size (px) inside the badge. */
export const NODE_STICKER_BASE_ICON_PX = 16
/** Base canvas emoji font size (px) before ds scale and user sticker scale. */
export const NODE_STICKER_BASE_CANVAS_FONT_PX = 12

/** Per-node marker in `node.properties.gfvSticker` (saved with the graph). */
export const NODE_STICKER_IDS = [
  'lightbulb',
  'skull',
  'heart',
  'star',
  'sparkles',
  'flame'
] as const

export type NodeStickerId = (typeof NODE_STICKER_IDS)[number]

export const NODE_STICKER_ICON_CLASS: Record<NodeStickerId, string> = {
  lightbulb: 'icon-[lucide--lightbulb]',
  skull: 'icon-[lucide--skull]',
  heart: 'icon-[lucide--heart]',
  star: 'icon-[lucide--star]',
  sparkles: 'icon-[lucide--sparkles]',
  flame: 'icon-[lucide--flame]'
}

export function stickerIconClassFor(
  id: string | undefined
): string | undefined {
  if (!id) return undefined
  return NODE_STICKER_ICON_CLASS[id as NodeStickerId]
}
