import { useNodeStickerPaletteStore } from '@/stores/nodeStickerPaletteStore'

const DEFAULT_STICKER_SCALE = 1.5

function clampScale(n: number): number {
  if (!Number.isFinite(n) || n <= 0) return DEFAULT_STICKER_SCALE
  return Math.min(2.5, Math.max(0.75, n))
}

/**
 * Safe read for sticker UI (Vue + canvas): uses palette store localStorage, not /settings.
 */
export function getNodeStickerScaleSafe(): number {
  try {
    const v = useNodeStickerPaletteStore().stickerScale as number
    return clampScale(typeof v === 'number' ? v : Number(v))
  } catch {
    return DEFAULT_STICKER_SCALE
  }
}
